let log = $json.body;
if (log?.body) log = log.body;

// 1. Identify the Windows Event Data path
const winData = log?.all_fields?.data?.win?.eventdata;

// 2. Extract IPs (Handles both standard Wazuh fields and Sysmon Event 3)
const src_ip = winData?.sourceIp || log?.all_fields?.srcip || log?.all_fields?.src_ip || null;
const dst_ip = winData?.destinationIp || log?.all_fields?.dstip || log?.all_fields?.dst_ip || null;

// 3. Extract SHA256 Hash (Regex handles the combined Sysmon hash string)
const raw_hashes = winData?.hashes || log?.all_fields?.hash || "";
const sha256_match = raw_hashes.match(/SHA256=([a-fA-F0-9]{64})/);
const file_hash = sha256_match ? sha256_match[1] : (log?.all_fields?.sha256 || null);

// 4. Return structured JSON
return [{ 
    json: { 
        ...log, 
        src_ip, 
        dst_ip, // Now included for your Level 10 test
        file_hash 
    } 
}];
